import { describe, it, expect, afterEach } from 'vitest';
import * as fs from 'fs';
import * as os from 'os';
import * as path from 'path';
import { clean } from '../src/commands/clean';

function makeTempDir(): string {
    return fs.mkdtempSync(path.join(os.tmpdir(), 'bi-clean-'));
}

describe('clean', () => {
    let tempDir: string;

    afterEach(() => {
        if (tempDir && fs.existsSync(tempDir)) {
            fs.rmSync(tempDir, { recursive: true, force: true });
        }
    });

    it('should identify node_modules for deletion', async () => {
        tempDir = makeTempDir();
        fs.mkdirSync(path.join(tempDir, 'node_modules'));
        fs.writeFileSync(path.join(tempDir, 'node_modules', 'test.txt'), 'hello');

        const result = await clean({ dryRun: true, cwd: tempDir });
        expect(result.deleted).toContain('node_modules');
    });

    it('should identify cache directories', async () => {
        tempDir = makeTempDir();
        fs.mkdirSync(path.join(tempDir, '.cache'));
        fs.mkdirSync(path.join(tempDir, '.next'));

        const result = await clean({ dryRun: true, cwd: tempDir });
        expect(result.deleted).toContain('.cache');
        expect(result.deleted).toContain('.next');
    });

    it('should support dry-run mode (no actual deletion)', async () => {
        tempDir = makeTempDir();
        fs.mkdirSync(path.join(tempDir, 'node_modules'));

        await clean({ dryRun: true, cwd: tempDir });
        expect(fs.existsSync(path.join(tempDir, 'node_modules'))).toBe(true);
    });

    it('should report freed bytes', async () => {
        tempDir = makeTempDir();
        fs.mkdirSync(path.join(tempDir, 'node_modules'));
        fs.writeFileSync(path.join(tempDir, 'node_modules', 'big.txt'), 'x'.repeat(1024));

        const result = await clean({ dryRun: true, cwd: tempDir });
        expect(result.freedBytes).toBeGreaterThan(0);
    });

    it('should actually delete in non-dry-run mode', async () => {
        tempDir = makeTempDir();
        fs.mkdirSync(path.join(tempDir, 'node_modules'));
        fs.writeFileSync(path.join(tempDir, 'node_modules', 'test.txt'), 'hello');

        await clean({ cwd: tempDir });
        expect(fs.existsSync(path.join(tempDir, 'node_modules'))).toBe(false);
    });

    it('should handle empty directory gracefully', async () => {
        tempDir = makeTempDir();

        const result = await clean({ cwd: tempDir });
        expect(result.deleted).toHaveLength(0);
        expect(result.freedBytes).toBe(0);
    });
});
